export class themeUtils{removeResourceLinksFromArray(e){e.forEach((e=>{document.querySelectorAll(`link[href^="${e.pathtoremove}${e.name}"], script[src^="${e.pathtoremove}${e.name}"]`).forEach((e=>{e.parentNode.removeChild(e)}))}))}addResourceLinksFromArray(e){e.forEach((e=>{let r;e.name.endsWith("css")?this.isFileDeclared(e.name,"css")||(r=document.createElement("link"),r.rel="stylesheet",r.href=e.pathtoadd+e.name,document.head.appendChild(r)):e.name.endsWith("js")&&(this.isFileDeclared(e.name,"js")||(r=document.createElement("script"),r.src=`${e.pathtoadd}${e.name}?lutece_h=${Math.random().toString(36).slice(2,11)}`,document.body.appendChild(r)))}))}replaceSourceLinksFromArray(e){this.removeResourceLinksFromArray(e),this.addResourceLinksFromArray(e)}isFileDeclared(e,r){let t=[];if("js"===r){t=document.body.getElementsByTagName("script");for(let r=0;r<t.length;r++)if(-1!==t[r].src.indexOf(e))return!0}else if("css"===r){t=document.head.getElementsByTagName("link");for(let r=0;r<t.length;r++)if(-1!==t[r].href.indexOf(e))return!0}return!1}}